@Slf4j
@PluginDescriptor(
	name = "Unmuted Jingles"
)
@PluginDependency(MusicPlugin.class)
public class UnmutedJinglesPlugin extends Plugin
{
	@Inject
	private Client client;

	@Inject
	private EventBus eventBus;

	@Inject
	private ClientThread clientThread;

	@Inject
	private MusicPlugin musicPlugin;

	@Inject
	private PluginManager pluginManager;

	@Inject
	private UnmutedJinglesConfig config;

	@Inject
	private JingleManager jingleManager;

	@Inject
	@Named("developerMode")
	boolean developerMode;

	//my workaround for not playing varbit-based jingles once logged in
	private int currentTime;

	@Override
	protected void startUp() throws Exception
	{
		currentTime = -1;
	}

	@Subscribe
	public void onGameStateChanged(GameStateChanged e){
		if (e.getGameState() == GameState.LOGGED_IN){
			//start timer
			currentTime = 0;
		}
	}

	@Subscribe
	public void onPluginChanged(PluginChanged e){

	}


	@Subscribe
	public void onVarbitChanged(VarbitChanged e){
		if (client.getMusicVolume() != 0 || isTimerTicking()) return;
		if (JingleData.VARBIT_JINGLE_INFOS.containsKey(e.getVarbitId())){
			jingleManager.playJingle(JingleData.VARBIT_JINGLE_INFOS.get(e.getVarbitId()));
		}
	}

	@Subscribe
	public void onConfigChanged(ConfigChanged e){
		log.debug(getName());
		if (e.getGroup().equals("unmutedjingles") && e.getKey().equals("jingleTest")){
			try{
				jingleManager.playJingle(JingleInfo.of("woodcutting_unlocks", JingleInfo.Type.LEVEL));
			}catch (Exception ex){
				log.debug("Failed test audio");
			}
		}
	}

	@Subscribe
	public void onGameTick(GameTick e){
		if (isTimerTicking()){
			currentTime++;
			if (currentTime >= 3){
				currentTime = -1;
				log.debug("Timer disabled");
			}
		}
		jingleManager.tickJingle();
	}

	@Subscribe
	public void onWidgetLoaded(WidgetLoaded e){
		if (client.getMusicVolume() != 0 || jingleManager.isLevelUpWidgetDisabled()) return;

		//If a level up display widget shows up, flag that it showed up; jingle queue handled in jinglemanager
		if (e.getGroupId() == InterfaceID.LEVELUP_DISPLAY){
			jingleManager.widgetLevelUp = true;
		}
	}

	@Subscribe
	public void onChatMessage(ChatMessage e){
		if(client.getMusicVolume() != 0 || !jingleManager.isLevelUpWidgetDisabled()) return;

		//If a level up chat message shows up, start queueing a jingle
		jingleManager.queueLevelJingle(e.getMessage());
	}

	@Provides
	UnmutedJinglesConfig provideConfig(ConfigManager configManager)
	{
		return configManager.getConfig(UnmutedJinglesConfig.class);
	}

	boolean isTimerTicking(){
		return currentTime != -1;
	}

	//debugging commands
	@Subscribe
	public void onCommandExecuted(CommandExecuted e)
	{
		if (!developerMode) return;

		String task = String.join(" ", e.getArguments());
		String skill = null;
		String skill2 = null;
		int level = 42;
		int level2 = 42;
		String command = e.getCommand();

		if (command.equals("uj-multi-level")){
			skill = StringUtils.capitalize(task.split(" ")[0].toLowerCase());
			skill2 = StringUtils.capitalize(task.split(" ")[2].toLowerCase());
			try
			{
				level = Integer.parseInt(task.split(" ")[1]);
				level2 = Integer.parseInt(task.split(" ")[3]);
			}
			catch (Exception ex)
			{
				// ignore
			}
			String msgTest0 = "Congratulations, you've just advanced your " + skill + " level. You are now level " + level + ".";
			String msgTest1 = "Congratulations, you've just advanced your " + skill2 + " level. You are now level " + level2 + ".";

			jingleManager.queueLevelJingle(msgTest0);
			jingleManager.queueLevelJingle(msgTest1);
		}else if (command.equals("uj-level")){
			skill = StringUtils.capitalize(task.split(" ")[0].toLowerCase());
			try
			{
				level = Integer.parseInt(task.split(" ")[1]);
			}
			catch (Exception ex)
			{
				// ignore
			}

			String msgTest = jingleManager.isLevelUpWidgetDisabled() ?
					"Congratulations, you've just advanced your " + skill + " level. You are now level " + level + "." :
					"Your "+ skill +" level is now " + level + ".";
			log.debug(msgTest);
			jingleManager.queueLevelJingle(msgTest);
		}else if (command.equals("uj-taskl")){
			VarbitChanged fake = new VarbitChanged();
			fake.setVarbitId(VarbitID.LEAGUE_TOTAL_TASKS_COMPLETED);
			fake.setValue(2);
			eventBus.post(fake);
		}else if (command.equals("uj-relicl")){
			VarbitChanged fake = new VarbitChanged();
			fake.setVarbitId(VarbitID.LEAGUE_RELIC_SELECTION_0);
			fake.setValue(2);
			eventBus.post(fake);
		}else if (command.equals("uj-priority")){
			VarbitChanged fake = new VarbitChanged();
			fake.setVarbitId(VarbitID.LEAGUE_TOTAL_TASKS_COMPLETED);
			fake.setValue(2);
			eventBus.post(fake);

			skill = StringUtils.capitalize(task.split(" ")[0].toLowerCase());
			try
			{
				level = Integer.parseInt(task.split(" ")[1]);
			}
			catch (Exception ex)
			{
				// ignore
			}

			String msgTest = jingleManager.isLevelUpWidgetDisabled() ?
					"Congratulations, you've just advanced your " + skill + " level. You are now level " + level + "." :
					"Your "+ skill +" level is now " + level + ".";
			log.debug(msgTest);
			jingleManager.queueLevelJingle(msgTest);
		}else if (command.equals("uj-combata")){
			VarbitChanged fake = new VarbitChanged();
			fake.setVarbitId(VarbitID.CA_TOTAL_TASKS_COMPLETED_EASY);
			fake.setValue(2);
			eventBus.post(fake);
		}

	}
}

package hootisman.unmutedjingles.jingles;

import hootisman.unmutedjingles.UnmutedJinglesConfig;
import javax.inject.Named;

import jaco.mp3.player.MP3Player;
import lombok.*;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Client;
import net.runelite.api.Skill;
import net.runelite.api.gameval.InterfaceID;
import net.runelite.api.gameval.VarbitID;
import net.runelite.api.widgets.Widget;
import net.runelite.client.RuneLite;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.util.Text;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.io.File;
import java.net.URL;
import java.util.HashMap;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

@Slf4j
@Singleton
public class JingleManager {

    @Inject
    private Client client;

    @Inject
    private ClientThread clientThread;

    @Inject
    private UnmutedJinglesConfig config;

	@Inject
	@Named("developerMode")
	boolean developerMode;

    //Taken from the runelite screenshot plugin, thanks guys!
    //widget level up message
    public static final Pattern LEVEL_UP_PATTERN = Pattern.compile(".*Your ([a-zA-Z]+) (?:level is|are)? now (\\d+)\\.");

    //chat level up message
    public static final Pattern LEVEL_UP_MESSAGE_PATTERN = Pattern.compile("Congratulations, you've (just advanced your (?<skill>[a-zA-Z]+) level\\. You are now level (?<level>\\d+)|reached the highest possible (?<skill99>[a-zA-Z]+) level of 99)\\.");
    public static final Map<String, URL> SOUNDS_CACHE = new HashMap<>();

    //true when a level up widget shows up, otherwise false
    public boolean widgetLevelUp;

    public MP3Player player;

    public JingleInfo currentSongInfo;

    public JingleManager(){
        widgetLevelUp = false;
    }

    public void tickJingle(){
        if (!widgetLevelUp || isLevelUpWidgetDisabled()) return;

        //widgets enabled + detected level up
        //Also from Screenshot Plugin
        Widget levelUpWidget = null;
        if (client.getWidget(InterfaceID.LevelupDisplay.TEXT2) != null) {
            levelUpWidget = client.getWidget(InterfaceID.LevelupDisplay.TEXT2);
        } else if (client.getWidget(InterfaceID.Objectbox.TEXT) != null &&
                !Text.removeTags(client.getWidget(InterfaceID.Objectbox.TEXT).getText()).contains("High level gamble")) {
            //probably the combat level widget? idk
            levelUpWidget = client.getWidget(InterfaceID.Objectbox.TEXT);
        }

        if (levelUpWidget != null) {
            queueLevelJingle(levelUpWidget.getText());
        }
        widgetLevelUp = false;
    }

    //true if levelup widget is disabled, otherwise false
    public boolean isLevelUpWidgetDisabled(){
        return client.getVarbitValue(VarbitID.OPTION_LEVEL_UP_MESSAGE_DISABLED) == 1;
    }

    //takes a chat/widget text, parses with regex, then tries to play a jingle
    public void queueLevelJingle(String message){
        Pattern regex = (isLevelUpWidgetDisabled() ? JingleManager.LEVEL_UP_MESSAGE_PATTERN : JingleManager.LEVEL_UP_PATTERN);
        Matcher m = regex.matcher(message);
        if (!m.matches()) return;

        String skill = (isLevelUpWidgetDisabled() ? m.group("skill") : m.group(1)).toUpperCase();
        String level = isLevelUpWidgetDisabled() ? m.group("level") : m.group(2);
        log.debug("Skill " + skill + " Level " + level);

        try {
            String fileName;
            if (skill.equals("COMBAT")){
                fileName = "combat";
            }else {
                Skill s = Skill.valueOf(skill);
                int l = Integer.parseInt(level);
                log.debug("Skill level parse successful");
                fileName = skill.toLowerCase() + (JingleData.UNLOCK_LEVELS.get(s).contains(l) ? "_unlocks" : "");
                log.debug("file name " + fileName);
            }
            playJingle(JingleInfo.of(fileName, JingleInfo.Type.LEVEL));
        }catch (Exception ex){
            log.debug("Failed to play level jingle");
        }
    }

    //loads and caches actual URL/mp3 clip
    public URL loadAndCache(String fileName){
        URL url = SOUNDS_CACHE.get(fileName);
        if (url == null){
            try {
                url = getClass().getResource(fileName);
                SOUNDS_CACHE.put(fileName, url);
            }catch (Exception ex){
                log.debug("Failed to find sound " + fileName);
                url = null;
            }
        }

        return url;
    }
    //1 no jingles playing=> create new
    //2 jingle playing, new jingle has priority => stop and create new
    //2 jingle playing, new jingle does not have priority => return
    public void playJingle(JingleInfo info){
        if (!info.isEnabled(config)) return;

        URL url = loadAndCache("/jinglesounds/" + info.type.folderName + "/" + info.fileName + ".mp3");
        if (url == null){
            log.debug("Failed to play jingle " + info.fileName);
            return;
        }
        if (player != null){
            if (currentSongInfo != null && player.isPlaying() && currentSongInfo.getPriority(config) < info.getPriority(config)) return;

            player.stop();
        }

        player = new MP3Player(url);
        player.setRepeat(false);
        player.setVolume(config.jingleGain());
        player.play();
        currentSongInfo = info;
    }
}

package hootisman.unmutedjingles.jingles;

import hootisman.unmutedjingles.UnmutedJinglesConfig;
import lombok.AllArgsConstructor;
import lombok.Getter;
import lombok.NonNull;
import lombok.RequiredArgsConstructor;
import net.runelite.api.gameval.SpriteID;

import javax.inject.Inject;

@RequiredArgsConstructor(staticName = "of")
public class JingleInfo{

    public enum Type{
        LEVEL("level"),
        LEAGUES("leagues"),
        OTHER("other");

        public final String folderName;
        private Type(String folderName){
            this.folderName = folderName;
        }
    }

    @Getter
    @NonNull
    String fileName;
    @Getter
    @NonNull
    Type type;
    /*
    @Getter
    @NonNull
    int startTime;

     */

    public int getPriority(UnmutedJinglesConfig config){
        int priority = 1;
        switch (type){
            case LEVEL:
                priority = config.levelPriority();
                break;
            case LEAGUES:
                priority = config.leaguesPriority();
                break;
            case OTHER:
                priority = config.otherPriority();
                break;
            default:
                break;
        }
        return priority;
    }

    public boolean isEnabled(UnmutedJinglesConfig config){
        boolean isEnabled = true;
        switch (type){
            case LEVEL:
                isEnabled = config.levelEnabled();
                break;
            case LEAGUES:
                isEnabled = config.leaguesEnabled();
                break;
            case OTHER:
                isEnabled = config.otherEnabled();
                break;
            default:
                break;
        }
        return isEnabled;
    }
}

